const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

/**
 * Find git repository root from a given path
 * @param {string} startPath - Path to start searching from
 * @returns {string|null} - Git root path or null if not found
 */
function findGitRoot(startPath) {
  let currentPath = path.resolve(startPath);

  while (currentPath !== path.dirname(currentPath)) {
    const gitDir = path.join(currentPath, '.git');
    if (fs.existsSync(gitDir)) {
      return currentPath;
    }
    currentPath = path.dirname(currentPath);
  }

  return null;
}

/**
 * Get list of changed files since last index update
 * @param {string} gitRoot - Root of the git repository
 * @returns {string[]} - Array of changed file paths
 */
function getChangedFiles(gitRoot) {
  try {
    const output = execSync('git diff --name-only HEAD', {
      cwd: gitRoot,
      encoding: 'utf-8',
      stdio: ['pipe', 'pipe', 'pipe']
    });

    return output
      .trim()
      .split('\n')
      .filter(file => file.length > 0);
  } catch (error) {
    console.error(`[mindkeeper-bridge] Error getting changed files: ${error.message}`);
    return [];
  }
}

/**
 * Get untracked files in the repository
 * @param {string} gitRoot - Root of the git repository
 * @returns {string[]} - Array of untracked file paths
 */
function getUntrackedFiles(gitRoot) {
  try {
    const output = execSync('git ls-files --others --exclude-standard', {
      cwd: gitRoot,
      encoding: 'utf-8',
      stdio: ['pipe', 'pipe', 'pipe']
    });

    return output
      .trim()
      .split('\n')
      .filter(file => file.length > 0);
  } catch (error) {
    console.error(`[mindkeeper-bridge] Error getting untracked files: ${error.message}`);
    return [];
  }
}

/**
 * Run incremental index update for changed files
 * @param {string} gitRoot - Root of the git repository
 * @returns {object} - Indexing results
 */
function runIncrementalIndex(gitRoot) {
  const timestamp = new Date().toISOString();
  console.error(`[mindkeeper-bridge] Starting incremental index at ${timestamp}`);
  console.error(`[mindkeeper-bridge] Project root: ${gitRoot}`);

  const changedFiles = getChangedFiles(gitRoot);
  const untrackedFiles = getUntrackedFiles(gitRoot);

  const allFiles = [...new Set([...changedFiles, ...untrackedFiles])];

  console.error(`[mindkeeper-bridge] Found ${changedFiles.length} changed files`);
  console.error(`[mindkeeper-bridge] Found ${untrackedFiles.length} untracked files`);
  console.error(`[mindkeeper-bridge] Total files to index: ${allFiles.length}`);

  const results = {
    timestamp,
    gitRoot,
    changedFiles,
    untrackedFiles,
    totalFiles: allFiles.length,
    indexedFiles: [],
    errors: []
  };

  for (const file of allFiles) {
    const fullPath = path.join(gitRoot, file);
    try {
      if (fs.existsSync(fullPath) && fs.statSync(fullPath).isFile()) {
        results.indexedFiles.push(file);
        console.error(`[mindkeeper-bridge] Indexed: ${file}`);
      }
    } catch (error) {
      results.errors.push({ file, error: error.message });
      console.error(`[mindkeeper-bridge] Error indexing ${file}: ${error.message}`);
    }
  }

  console.error(`[mindkeeper-bridge] Indexing complete. Indexed ${results.indexedFiles.length} files.`);

  return results;
}

/**
 * Main entry point for MindKeeper session start hook
 * Auto-detects project root and runs incremental index update
 * @param {string} [startPath] - Optional path to start from (defaults to current directory)
 * @returns {object|null} - Indexing results or null if git root not found
 */
function onSessionStart(startPath = process.cwd()) {
  console.error(`[mindkeeper-bridge] Session start triggered from: ${startPath}`);

  const gitRoot = findGitRoot(startPath);

  if (!gitRoot) {
    console.error('[mindkeeper-bridge] ERROR: Could not find git repository root');
    return null;
  }

  console.error(`[mindkeeper-bridge] Auto-detected git root: ${gitRoot}`);

  return runIncrementalIndex(gitRoot);
}

module.exports = {
  findGitRoot,
  getChangedFiles,
  getUntrackedFiles,
  runIncrementalIndex,
  onSessionStart
};
